package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setup() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testPrint() throws IOException {
        // Given
        Appendable out = new StringWriter();
        Object object = null;
        CharSequence value = "test";
        int offset = 0;
        int len = value.length();
        boolean newRecord = true;

        // When
        csvFormat.print(object, value, offset, len, out, newRecord);

        // Then
        assertEquals(value, out.toString());
    }

    @Test
    public void testPrintWithObject() throws IOException {
        // Given
        Appendable out = new StringWriter();
        Object object = 123;
        CharSequence value = "456";
        int offset = 0;
        int len = value.length();
        boolean newRecord = true;

        // When
        csvFormat.print(object, value, offset, len, out, newRecord);

        // Then
        assertEquals("\"456\"", out.toString());
    }

    @Test
    public void testPrintAndEscape() throws IOException {
        // Given
        Appendable out = new StringWriter();
        CharSequence value = "te,st";
        int offset = 0;
        int len = value.length();

        // When
        csvFormat.printAndEscape(value, offset, len, out);

        // Then
        assertEquals("te\\,st", out.toString());
    }

    @Test
    public void testPrintAndQuote() throws IOException {
        // Given
        Appendable out = new StringWriter();
        Object object = 123;
        CharSequence value = "456";
        int offset = 0;
        int len = value.length();
        boolean newRecord = true;

        // When
        csvFormat.printAndQuote(object, value, offset, len, out, newRecord);

        // Then
        assertEquals("\"456\"", out.toString());
    }
}
